{% extends "base.html" %}
{% load games_extras %}

{% block title %}Punkte eintragen - Spiel #{{ game.id }}{% endblock %}

{% block content %}
<div class="card">
    <h2>Punkte eintragen – Spiel #{{ game.id }}</h2>
    <p class="small">Trage für jede Kategorie und jeden Spieler die erzielten Punkte ein. Bei festen Kategorien wähle „Gewürfelt“ oder „Gestrichen“. Änderungen werden automatisch gespeichert.</p>

    <form method="post" action="{% url 'game_score' game.pk %}">
        {% csrf_token %}

        <div class="score-sheet-wrapper">
            <table class="score-sheet">
            <thead>
                <tr>
                    <th>Kategorie</th>
                    {% for gp in players %}
                        <th>{{ gp.player.name }}</th>
                    {% endfor %}
                </tr>
            </thead>

            <tbody>
                {% for category in upper_categories %}
                    <tr>
                        <td>{{ category.label }}{% if category in fixed_points %} ({{ fixed_points|get_item:category }} Pkte){% endif %}</td>
                        {% for gp in players %}
                            {% with entry=gp.scores_by_category|get_item:category.value %}
                                <td>
                                    {% if category in fixed_points %}
                                        <select
                                            name="state_{{ gp.pk }}_{{ category.value }}"
                                            hx-post="{% url 'game_score_partial' game.pk %}"
                                            hx-trigger="change"
                                            hx-target="#upper-totals"
                                            hx-swap="outerHTML"
                                            hx-vals='{"game_player_id": "{{ gp.pk }}", "category": "{{ category.value }}"}'
                                        >
                                            <option value="" {% if not entry or entry.is_empty %}selected{% endif %}>—</option>
                                            <option value="filled" {% if entry and entry.is_filled %}selected{% endif %}>Gewürfelt</option>
                                            <option value="stricken" {% if entry and entry.is_stricken %}selected{% endif %}>Gestrichen</option>
                                        </select>
                                    {% else %}
                                        <input
                                            type="number"
                                            name="score_{{ gp.pk }}_{{ category.value }}"
                                            min="0"
                                            value="{% if entry and entry.is_filled %}{{ entry.value|default:'' }}{% endif %}"
                                            hx-post="{% url 'game_score_partial' game.pk %}"
                                            hx-trigger="change"
                                            hx-target="#upper-totals"
                                            hx-swap="outerHTML"
                                            hx-vals='{"game_player_id": "{{ gp.pk }}", "category": "{{ category.value }}"}'
                                        >
                                    {% endif %}
                                </td>
                            {% endwith %}
                        {% endfor %}
                    </tr>
                {% endfor %}
            </tbody>

            <tbody id="upper-totals">
                {% include "games/_score_totals_upper.html" %}
            </tbody>

            <tbody>
                {% for category in lower_categories %}
                    <tr>
                        <td>{{ category.label }}{% if category in fixed_points %} ({{ fixed_points|get_item:category }} Pkte){% endif %}</td>
                        {% for gp in players %}
                            {% with entry=gp.scores_by_category|get_item:category.value %}
                                <td>
                                    {% if category in fixed_points %}
                                        <select
                                            name="state_{{ gp.pk }}_{{ category.value }}"
                                            hx-post="{% url 'game_score_partial' game.pk %}"
                                            hx-trigger="change"
                                            hx-target="#upper-totals"
                                            hx-swap="outerHTML"
                                            hx-vals='{"game_player_id": "{{ gp.pk }}", "category": "{{ category.value }}"}'
                                        >
                                            <option value="" {% if not entry or entry.is_empty %}selected{% endif %}>—</option>
                                            <option value="filled" {% if entry and entry.is_filled %}selected{% endif %}>Gewürfelt</option>
                                            <option value="stricken" {% if entry and entry.is_stricken %}selected{% endif %}>Gestrichen</option>
                                        </select>
                                    {% else %}
                                        <input
                                            type="number"
                                            name="score_{{ gp.pk }}_{{ category.value }}"
                                            min="0"
                                            value="{% if entry and entry.is_filled %}{{ entry.value|default:'' }}{% endif %}"
                                            hx-post="{% url 'game_score_partial' game.pk %}"
                                            hx-trigger="change"
                                            hx-target="#upper-totals"
                                            hx-swap="outerHTML"
                                            hx-vals='{"game_player_id": "{{ gp.pk }}", "category": "{{ category.value }}"}'
                                        >
                                    {% endif %}
                                </td>
                            {% endwith %}
                        {% endfor %}
                    </tr>
                {% endfor %}
            </tbody>

            <tbody id="lower-totals">
                {% include "games/_score_totals_lower.html" %}
            </tbody>
        </table>
        </div>

        <div class="actions">
            <button type="submit" class="btn btn-success">Punkte speichern</button>
            <a href="{% url 'game_detail' game.pk %}" class="btn btn-secondary">Zurück</a>
        </div>
    </form>
</div>

<style>
    .score-sheet-wrapper {
        overflow-x: auto;
        -webkit-overflow-scrolling: touch;
        margin: 1rem 0;
    }
    .score-sheet {
        min-width: 100%;
        table-layout: auto;
    }
    .score-sheet th:first-child,
    .score-sheet td:first-child {
        position: sticky;
        left: 0;
        background: #fff;
        z-index: 1;
        min-width: 140px;
        box-shadow: 2px 0 4px rgba(0,0,0,0.05);
    }
    .score-sheet th {
        background: #f0f1f5;
    }
    .score-sheet input[type="number"],
    .score-sheet select {
        min-width: 80px;
        max-width: 120px;
    }
    .sum-row td, .sum-row th { background: #eef2f7; font-weight: bold; }
    .bonus-row td, .bonus-row th { font-weight: bold; }
    .bonus-achieved { color: #27ae60; background: #eafaf1 !important; }
    .bonus-missed { color: #c0392b; background: #fdecea !important; }
    select { min-width: 110px; }

    @media (max-width: 700px) {
        .score-sheet th:first-child,
        .score-sheet td:first-child {
            min-width: 120px;
            font-size: 0.9rem;
        }
        .score-sheet th,
        .score-sheet td {
            padding: 0.45rem;
        }
        .score-sheet input[type="number"],
        .score-sheet select {
            font-size: 1rem;
            padding: 0.4rem;
        }
    }
</style>
{% endblock %}

